module sr_flip_flop (
    input wire clk,
    input wire S,
    input wire R,
    output reg obf_Q,
    output wire Qbar
);
    assign Qbar = ~obf_Q;

    always @(posedge clk) begin
        if (S && R)
            obf_Q <= 0;  // Invalid state
        else if (S)
            obf_Q <= 1;  // Set state
        else if (R)
            obf_Q <= 0;  // Reset state
        // Else obf_Q retains its previous state
    end
endmodule
